#!/usr/bin/env node
// Classes 3-5 prose generator (English, Science, Social Studies) — no API key.
//
// English: grammar MCQs (plurals, past tense, opposites, synonyms, articles,
// parts of speech). Choices stay in English on purpose — the subject IS the
// English words. Only the prompt templates carry 13-language text.
//
// Science / Social Studies: curated fact bank. Prompts are hand-translated
// once; answers/distractors come from the shared curated vocabulary
// (i18n-345.mjs + Class 1/2 word lists). Numeric answers and emoji visuals are
// used wherever possible — they need no translation at all.
//
// Usage: node scripts/generate-class345-prose.mjs [--dry]

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";
import { VOCAB as CORE, trObj } from "./generate-primary-prose.mjs";
import { EXTRA as C2 } from "./generate-class2-prose.mjs";
import { WORDS } from "./i18n-345.mjs";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, "..");
const DRY = process.argv.slice(2).includes("--dry");

const byEn = {};
for (const w of [...CORE, ...C2]) byEn[w.en] = w;
for (const k of Object.keys(WORDS)) byEn[k] = WORDS[k]; // key: e.g. "FlowerP"
const T = (k) => { if (!byEn[k]) throw new Error(`unknown word key ${k}`); return trObj(byEn[k]); };
const NUM = (n) => ({ en: String(n) });   // numeric choice — language-neutral
const EN = (s) => ({ en: s });            // English-only choice (grammar)

function rng(seed) { return function () { seed |= 0; seed = (seed + 0x6D2B79F5) | 0; let t = Math.imul(seed ^ (seed >>> 15), 1 | seed); t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t; return ((t ^ (t >>> 14)) >>> 0) / 4294967296; }; }
const shuffle = (r, a) => [...a].sort(() => r() - 0.5);

function mcq(id, prompt, correctObj, distractorObjs, slot, visual) {
  const choices = []; let di = 0;
  for (let i = 0; i < 4; i++) choices.push(i === slot ? correctObj : distractorObjs[di++]);
  const q = { id, type: "mcq", prompt, choices, answerIndex: slot };
  if (visual) q.visual = visual;
  return q;
}

// ── English prompt templates (cue word stays English — it's the subject) ──
const tpl = (mk) => (w) => { const t = {}; for (const [l, f] of Object.entries(mk)) t[l] = f(w); return t; };
export const P_PLURAL = tpl({ en:w=>`What is the plural of "${w}"?`, hi:w=>`"${w}" का बहुवचन क्या है?`, ta:w=>`"${w}" இன் பன்மை என்ன?`, te:w=>`"${w}" యొక్క బహువచనం ఏమిటి?`, bn:w=>`"${w}" এর বহুবচন কী?`, mr:w=>`"${w}" चे अनेकवचन काय आहे?`, gu:w=>`"${w}" નું બહુવચન શું છે?`, kn:w=>`"${w}" ದ ಬಹುವಚನ ಯಾವುದು?`, ml:w=>`"${w}" ന്റെ ബഹുവചനം എന്ത്?`, pa:w=>`"${w}" ਦਾ ਬਹੁਵਚਨ ਕੀ ਹੈ?`, ur:w=>`"${w}" کی جمع کیا ہے؟`, or:w=>`"${w}" ର ବହୁବଚନ କ'ଣ?`, ne:w=>`"${w}" को बहुवचन के हो?` });
export const P_PAST = tpl({ en:w=>`What is the past tense of "${w}"?`, hi:w=>`"${w}" का भूतकाल क्या है?`, ta:w=>`"${w}" இன் இறந்த காலம் என்ன?`, te:w=>`"${w}" యొక్క భూతకాలం ఏమిటి?`, bn:w=>`"${w}" এর অতীত কাল কী?`, mr:w=>`"${w}" चा भूतकाळ काय आहे?`, gu:w=>`"${w}" નો ભૂતકાળ શું છે?`, kn:w=>`"${w}" ದ ಭೂತಕಾಲ ಯಾವುದು?`, ml:w=>`"${w}" ന്റെ ഭൂതകാലം എന്ത്?`, pa:w=>`"${w}" ਦਾ ਭੂਤਕਾਲ ਕੀ ਹੈ?`, ur:w=>`"${w}" کا ماضی کیا ہے؟`, or:w=>`"${w}" ର ଅତୀତ କାଳ କ'ଣ?`, ne:w=>`"${w}" को भूतकाल के हो?` });
export const P_OPP = tpl({ en:w=>`What is the opposite of "${w}"?`, hi:w=>`"${w}" का विलोम क्या है?`, ta:w=>`"${w}" இன் எதிர்ச்சொல் என்ன?`, te:w=>`"${w}" కి వ్యతిరేక పదం ఏమిటి?`, bn:w=>`"${w}" এর বিপরীত শব্দ কী?`, mr:w=>`"${w}" चा विरुद्धार्थी शब्द कोणता?`, gu:w=>`"${w}" નો વિરોધી શબ્દ કયો છે?`, kn:w=>`"${w}" ದ ವಿರುದ್ಧ ಪದ ಯಾವುದು?`, ml:w=>`"${w}" ന്റെ വിപരീത പദം എന്ത്?`, pa:w=>`"${w}" ਦਾ ਉਲਟ ਸ਼ਬਦ ਕੀ ਹੈ?`, ur:w=>`"${w}" کا متضاد کیا ہے؟`, or:w=>`"${w}" ର ବିପରୀତ ଶବ୍ଦ କ'ଣ?`, ne:w=>`"${w}" को विपरीत शब्द के हो?` });
export const P_SYN = tpl({ en:w=>`Which word means the same as "${w}"?`, hi:w=>`कौन सा शब्द "${w}" के समान अर्थ रखता है?`, ta:w=>`"${w}" போன்ற பொருள் கொண்ட சொல் எது?`, te:w=>`"${w}" తో సమాన అర్థం గల పదం ఏది?`, bn:w=>`কোন শব্দের অর্থ "${w}" এর মতো?`, mr:w=>`कोणत्या शब्दाचा अर्थ "${w}" सारखा आहे?`, gu:w=>`કયા શબ્દનો અર્થ "${w}" જેવો છે?`, kn:w=>`"${w}" ದಂತೆಯೇ ಅರ್ಥವಿರುವ ಪದ ಯಾವುದು?`, ml:w=>`"${w}" ന്റെ അതേ അർത്ഥമുള്ള വാക്ക് ഏത്?`, pa:w=>`ਕਿਹੜੇ ਸ਼ਬਦ ਦਾ ਅਰਥ "${w}" ਵਰਗਾ ਹੈ?`, ur:w=>`کون سا لفظ "${w}" جیسا معنی رکھتا ہے؟`, or:w=>`କେଉଁ ଶବ୍ଦର ଅର୍ଥ "${w}" ପରି?`, ne:w=>`कुन शब्दको अर्थ "${w}" जस्तै हो?` });
const P_ARTICLE = { en:"Which is correct?", hi:"कौन सा सही है?", ta:"எது சரியானது?", te:"ఏది సరైనది?", bn:"কোনটি সঠিক?", mr:"कोणते बरोबर आहे?", gu:"કયું સાચું છે?", kn:"ಯಾವುದು ಸರಿ?", ml:"ഏതാണ് ശരി?", pa:"ਕਿਹੜਾ ਸਹੀ ਹੈ?", ur:"کون سا درست ہے؟", or:"କେଉଁଟି ଠିକ୍?", ne:"कुन सही हो?" };
export const P_POS = {
  noun:      { en:"Which word is a noun?", hi:"कौन सा शब्द संज्ञा है?", ta:"எந்த சொல் பெயர்ச்சொல்?", te:"ఏ పదం నామవాచకం?", bn:"কোন শব্দটি বিশেষ্য?", mr:"कोणता शब्द नाम आहे?", gu:"કયો શબ્દ સંજ્ઞા છે?", kn:"ಯಾವ ಪದ ನಾಮಪದ?", ml:"ഏത് വാക്കാണ് നാമം?", pa:"ਕਿਹੜਾ ਸ਼ਬਦ ਨਾਂਵ ਹੈ?", ur:"کون سا لفظ اسم ہے؟", or:"କେଉଁ ଶବ୍ଦ ବିଶେଷ୍ୟ?", ne:"कुन शब्द नाम हो?" },
  verb:      { en:"Which word is a verb?", hi:"कौन सा शब्द क्रिया है?", ta:"எந்த சொல் வினைச்சொல்?", te:"ఏ పదం క్రియ?", bn:"কোন শব্দটি ক্রিয়া?", mr:"कोणता शब्द क्रियापद आहे?", gu:"કયો શબ્દ ક્રિયાપદ છે?", kn:"ಯಾವ ಪದ ಕ್ರಿಯಾಪದ?", ml:"ഏത് വാക്കാണ് ക്രിയ?", pa:"ਕਿਹੜਾ ਸ਼ਬਦ ਕਿਰਿਆ ਹੈ?", ur:"کون سا لفظ فعل ہے؟", or:"କେଉଁ ଶବ୍ଦ କ୍ରିୟା?", ne:"कुन शब्द क्रिया हो?" },
  adjective: { en:"Which word is an adjective?", hi:"कौन सा शब्द विशेषण है?", ta:"எந்த சொல் பெயரடை?", te:"ఏ పదం విశేషణం?", bn:"কোন শব্দটি বিশেষণ?", mr:"कोणता शब्द विशेषण आहे?", gu:"કયો શબ્દ વિશેષણ છે?", kn:"ಯಾವ ಪದ ಗುಣವಾಚಕ?", ml:"ഏത് വാക്കാണ് വിശേഷണം?", pa:"ਕਿਹੜਾ ਸ਼ਬਦ ਵਿਸ਼ੇਸ਼ਣ ਹੈ?", ur:"کون سا لفظ صفت ہے؟", or:"କେଉଁ ଶବ୍ଦ ବିଶେଷଣ?", ne:"कुन शब्द विशेषण हो?" },
  adverb:    { en:"Which word is an adverb?", hi:"कौन सा शब्द क्रियाविशेषण है?", ta:"எந்த சொல் வினையடை?", te:"ఏ పదం క్రియా విశేషణం?", bn:"কোন শব্দটি ক্রিয়া বিশেষণ?", mr:"कोणता शब्द क्रियाविशेषण आहे?", gu:"કયો શબ્દ ક્રિયાવિશેષણ છે?", kn:"ಯಾವ ಪದ ಕ್ರಿಯಾವಿಶೇಷಣ?", ml:"ഏത് വാക്കാണ് ക്രിയാവിശേഷണം?", pa:"ਕਿਹੜਾ ਸ਼ਬਦ ਕਿਰਿਆ ਵਿਸ਼ੇਸ਼ਣ ਹੈ?", ur:"کون سا لفظ متعلق فعل ہے؟", or:"କେଉଁ ଶବ୍ଦ କ୍ରିୟା ବିଶେଷଣ?", ne:"कुन शब्द क्रियाविशेषण हो?" },
};

// ── English word tables (answer + 3 hand-picked wrong forms) ──
const PLU = {
  3: [["cat","cats",["cates","catss","caties"]],["dog","dogs",["doges","dogies","dogs'"]],["box","boxes",["boxs","boxies","boxen"]],["bus","buses",["buss","busies","busen"]],["baby","babies",["babys","babyes","babbies"]],["story","stories",["storys","storyes","storis"]],["man","men",["mans","manes","mens"]],["child","children",["childs","childes","childrens"]],["foot","feet",["foots","footes","feets"]],["tooth","teeth",["tooths","toothes","teeths"]],["mouse","mice",["mouses","mousies","mices"]],["woman","women",["womans","womanes","womens"]]],
  4: [["leaf","leaves",["leafs","leafes","leavs"]],["knife","knives",["knifes","knifies","knive"]],["wolf","wolves",["wolfs","wolfes","wolvs"]],["shelf","shelves",["shelfs","shelfes","shelvs"]],["life","lives",["lifes","lifies","live"]],["thief","thieves",["thiefs","thiefes","thievs"]]],
  5: [["sheep","sheep",["sheeps","sheepes","shoop"]],["deer","deer",["deers","deeres","dear"]],["goose","geese",["gooses","geeses","goosen"]],["ox","oxen",["oxes","oxs","oxies"]]],
};
const PAST = {
  4: [["play","played",["plaid","playd","plays"]],["jump","jumped",["jumpt","jumpd","jumps"]],["go","went",["goed","gone","going"]],["eat","ate",["eated","eaten","eats"]],["come","came",["comed","come","comes"]],["run","ran",["runned","runed","runs"]],["see","saw",["seed","seen","sees"]],["write","wrote",["writed","written","writes"]],["take","took",["taked","taken","takes"]],["give","gave",["gived","given","gives"]],["sing","sang",["singed","sung","sings"]],["drink","drank",["drinked","drunk","drinks"]]],
  5: [["buy","bought",["buyed","brought","buys"]],["teach","taught",["teached","tought","teaches"]],["catch","caught",["catched","cought","catches"]],["think","thought",["thinked","thunk","thinks"]],["bring","brought",["bringed","bought","brings"]],["fight","fought",["fighted","fit","fights"]]],
};
const OPP = {
  3: [["tall","short"],["fat","thin"],["full","empty"],["near","far"],["clean","dirty"],["hard","soft"],["heavy","light"],["first","last"],["above","below"],["inside","outside"]],
  4: [["early","late"],["strong","weak"],["loud","quiet"],["rich","poor"],["always","never"],["win","lose"],["buy","sell"],["laugh","cry"],["remember","forget"],["push","pull"]],
  5: [["arrive","depart"],["ancient","modern"],["victory","defeat"],["increase","decrease"],["maximum","minimum"],["presence","absence"],["entrance","exit"],["success","failure"]],
};
const SYN = {
  4: [["big","large"],["small","little"],["happy","glad"],["fast","quick"],["smart","clever"],["angry","mad"],["sad","unhappy"],["begin","start"],["end","finish"],["loud","noisy"]],
  5: [["brave","courageous"],["famous","well-known"],["difficult","hard"],["easy","simple"],["silent","quiet"],["gift","present"],["smart","intelligent"],["quick","rapid"],["tidy","neat"],["mistake","error"]],
};
// nouns starting with vowel sound take "an"
const ART = [["apple","an"],["egg","an"],["orange","an"],["umbrella","an"],["elephant","an"],["book","a"],["cat","a"],["banana","a"]];
const POS_WORDS = {
  noun: ["school","river","chair","mango","honesty","knowledge"],
  verb: ["jump","swim","read","dance","decide","arrive"],
  adjective: ["tall","sweet","round","bright"],
  adverb: ["slowly","quickly","loudly","softly"],
};

function buildEnglish(cls) {
  const r = rng(300 + cls); const out = []; let n = 1;
  const id = () => `${cls}-english-gen-${String(n++).padStart(3, "0")}`;
  const push = (prompt, ans, ds) => out.push(mcq(id(), prompt, EN(ans), ds.map(EN), out.length % 4));
  for (const [base, ans, ds] of PLU[cls] || []) push(P_PLURAL(base), ans, ds);
  for (const [base, ans, ds] of PAST[cls] || []) push(P_PAST(base), ans, ds);
  for (const [cue, ans] of OPP[cls] || []) {
    const others = OPP[cls].flat().filter((w) => w !== cue && w !== ans);
    push(P_OPP(cue), ans, shuffle(r, others).slice(0, 3));
  }
  for (const [cue, ans] of SYN[cls] || []) {
    // distractors: other cue words (never the answer's synonym partner)
    const others = SYN[cls].map(([c]) => c).filter((w) => w !== cue && w !== ans);
    push(P_SYN(cue), ans, shuffle(r, others).slice(0, 3));
  }
  if (cls === 3) {
    for (const [nounW, art] of ART) {
      const wrong = art === "an" ? "a" : "an";
      // distractors: wrong article on same noun + two wrong-article phrases
      const otherPool = ART.filter(([m]) => m !== nounW).map(([m, a]) => `${a === "an" ? "a" : "an"} ${m}`);
      push(P_ARTICLE, `${art} ${nounW}`, [`${wrong} ${nounW}`, ...shuffle(r, otherPool).slice(0, 2)]);
    }
    for (const ans of POS_WORDS.noun.slice(0, 4)) push(P_POS.noun, ans, shuffle(r, [...POS_WORDS.verb.slice(0,4), ...POS_WORDS.adjective]).slice(0, 3));
    for (const ans of POS_WORDS.verb.slice(0, 4)) push(P_POS.verb, ans, shuffle(r, [...POS_WORDS.noun.slice(0,4), ...POS_WORDS.adjective]).slice(0, 3));
  }
  if (cls === 5) {
    for (const ans of POS_WORDS.adjective) push(P_POS.adjective, ans, shuffle(r, [...POS_WORDS.noun, ...POS_WORDS.verb]).slice(0, 3));
    for (const ans of POS_WORDS.adverb) push(P_POS.adverb, ans, shuffle(r, [...POS_WORDS.noun, ...POS_WORDS.adjective]).slice(0, 3));
    for (const ans of POS_WORDS.noun.slice(4)) push(P_POS.noun, ans, shuffle(r, [...POS_WORDS.verb, ...POS_WORDS.adverb]).slice(0, 3));
    for (const ans of POS_WORDS.verb.slice(4)) push(P_POS.verb, ans, shuffle(r, [...POS_WORDS.noun.slice(0,4), ...POS_WORDS.adverb]).slice(0, 3));
  }
  return out;
}

// ── Fact bank: F(promptObj, answerKey, [distractorKeys], visual?) ──
// Keys reference translated words (T) — or use n() for numeric facts.
const F = (p, ans, ds, visual) => ({ p, ans, ds, visual });
const FN = (p, ans, ds) => ({ p, ans: String(ans), ds: ds.map(String), numeric: true });

